import os
import pickle
import json
import time
from functools import wraps
from pathlib import Path
from typing import Any, Optional, Callable
from flask import Flask, request, jsonify
import hashlib


class DiskCache:
    def __init__(self, cache_dir: str = 'cache', default_ttl: int = 3600):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(exist_ok=True)
        self.default_ttl = default_ttl
        
    def _get_cache_path(self, key: str) -> Path:
        safe_key = hashlib.md5(key.encode()).hexdigest()
        return self.cache_dir / f"{safe_key}.pkl"
    
    def _get_metadata_path(self, key: str) -> Path:
        safe_key = hashlib.md5(key.encode()).hexdigest()
        return self.cache_dir / f"{safe_key}.meta"
    
    def set(self, key: str, value: Any, ttl: Optional[int] = None) -> None:
        cache_path = self._get_cache_path(key)
        meta_path = self._get_metadata_path(key)
        
        ttl = ttl if ttl is not None else self.default_ttl
        expiry_time = time.time() + ttl
        
        with open(cache_path, 'wb') as f:
            pickle.dump(value, f, protocol=pickle.HIGHEST_PROTOCOL)
        
        metadata = {
            'expiry': expiry_time,
            'created': time.time(),
            'key': key
        }
        
        with open(meta_path, 'w') as f:
            json.dump(metadata, f)
    
    def get(self, key: str) -> Optional[Any]:
        cache_path = self._get_cache_path(key)
        meta_path = self._get_metadata_path(key)
        
        if not cache_path.exists() or not meta_path.exists():
            return None
        
        with open(meta_path, 'r') as f:
            metadata = json.load(f)
        
        if time.time() > metadata['expiry']:
            self.delete(key)
            return None
        
        with open(cache_path, 'rb') as f:
            return pickle.load(f)
    
    def delete(self, key: str) -> None:
        cache_path = self._get_cache_path(key)
        meta_path = self._get_metadata_path(key)
        
        if cache_path.exists():
            cache_path.unlink()
        if meta_path.exists():
            meta_path.unlink()
    
    def clear(self) -> None:
        for file_path in self.cache_dir.glob('*'):
            file_path.unlink()
    
    def get_stats(self) -> dict:
        cache_files = list(self.cache_dir.glob('*.pkl'))
        total_size = sum(f.stat().st_size for f in cache_files)
        
        valid_count = 0
        expired_count = 0
        
        for meta_file in self.cache_dir.glob('*.meta'):
            with open(meta_file, 'r') as f:
                metadata = json.load(f)
                if time.time() <= metadata['expiry']:
                    valid_count += 1
                else:
                    expired_count += 1
        
        return {
            'total_entries': len(cache_files),
            'valid_entries': valid_count,
            'expired_entries': expired_count,
            'total_size_bytes': total_size
        }


def cache_response(ttl: Optional[int] = None, key_func: Optional[Callable] = None):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache = getattr(wrapper, '_cache', None)
            if cache is None:
                return func(*args, **kwargs)
            
            if key_func:
                cache_key = key_func(*args, **kwargs)
            else:
                cache_key = f"{func.__name__}:{request.path}:{request.query_string.decode()}"
            
            cached_data = cache.get(cache_key)
            if cached_data is not None:
                return jsonify({
                    'data': cached_data,
                    'cached': True,
                    'timestamp': time.time()
                })
            
            result = func(*args, **kwargs)
            
            if hasattr(result, 'get_json'):
                data = result.get_json()
            elif isinstance(result, tuple) and len(result) > 0:
                data = result[0].get_json() if hasattr(result[0], 'get_json') else result[0]
            else:
                data = result
            
            cache.set(cache_key, data, ttl=ttl)
            
            return jsonify({
                'data': data,
                'cached': False,
                'timestamp': time.time()
            })
        
        return wrapper
    return decorator


